  1→/**
  2→ * OAuth2 authorization flow helpers for credential providers.
  3→ *
  4→ * Pure functions for building authorization URLs and exchanging codes for tokens.
  5→ * State management uses an in-memory map (sufficient for walking skeleton;
  6→ * production should use short-lived DB records).
  7→ *
  8→ * ADR-066, ADR-068.
  9→ */
 10→
 11→import type { CredentialProviderRecord, PkceChallenge, AuthorizationParams, TokenExchangeParams, TokenResult } from "./types";
 12→
 13→// ---------------------------------------------------------------------------
 14→// State Store -- in-memory map keyed by state parameter
 15→// ---------------------------------------------------------------------------
 16→
 17→export type OAuthStateEntry = {
 18→  providerId: string;
 19→  identityId: string;
 20→  workspaceId: string;
 21→  createdAt: number;
 22→};
 23→
 24→const pendingStates = new Map<string, OAuthStateEntry>();
 25→
 26→/** TTL for state entries: 10 minutes */
 27→const STATE_TTL_MS = 10 * 60 * 1000;
 28→
 29→/**
 30→ * Store a state parameter for later verification during callback.
 31→ */
 32→export function storeOAuthState(state: string, entry: OAuthStateEntry): void {
 33→  pendingStates.set(state, entry);
 34→}
 35→
 36→/**
 37→ * Retrieve and consume a state entry. Returns undefined if not found or expired.
 38→ */
 39→export function consumeOAuthState(state: string): OAuthStateEntry | undefined {
 40→  const entry = pendingStates.get(state);
 41→  if (!entry) return undefined;
 42→
 43→  pendingStates.delete(state);
 44→
 45→  const elapsed = Date.now() - entry.createdAt;
 46→  if (elapsed > STATE_TTL_MS) return undefined;
 47→
 48→  return entry;
 49→}
 50→
 51→// ---------------------------------------------------------------------------
 52→// PKCE S256 Generation
 53→// ---------------------------------------------------------------------------
 54→
 55→/**
 56→ * Generate a PKCE code_verifier and code_challenge (S256).
 57→ * Uses Web Crypto API (available in Bun natively).
 58→ *
 59→ * code_verifier: 64 characters from unreserved set [A-Za-z0-9-._~]
 60→ * code_challenge: BASE64URL(SHA256(code_verifier))
 61→ */
 62→export async function generatePkce(): Promise<PkceChallenge> {
 63→  const codeVerifier = generateCodeVerifier(64);
 64→  const codeChallenge = await computeS256Challenge(codeVerifier);
 65→  return { codeVerifier, codeChallenge };
 66→}
 67→
 68→/** Generate a random code_verifier of specified length using unreserved characters. */
 69→function generateCodeVerifier(length: number): string {
 70→  // RFC 7636 unreserved characters
 71→  const unreservedChars = "REDACTED._~";
 72→  const randomBytes = crypto.getRandomValues(new Uint8Array(length));
 73→  let verifier = "";
 74→  for (const byte of randomBytes) {
 75→    verifier += unreservedChars[byte % unreservedChars.length];
 76→  }
 77→  return verifier;
 78→}
 79→
 80→/** Compute BASE64URL(SHA256(verifier)) with no padding. */
 81→async function computeS256Challenge(verifier: string): Promise<string> {
 82→  const encoder = new TextEncoder();
 83→  const digest = await crypto.subtle.digest("SHA-256", encoder.encode(verifier));
 84→  return base64UrlEncode(digest);
 85→}
 86→
 87→/** Base64url encode an ArrayBuffer (no padding). */
 88→function base64UrlEncode(buffer: ArrayBuffer): string {
 89→  const bytes = new Uint8Array(buffer);
 90→  let binary = "";
 91→  for (const byte of bytes) {
 92→    binary += String.fromCharCode(byte);
 93→  }
 94→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// PKCE-Aware Authorization URL Builder
 99→// ---------------------------------------------------------------------------
100→
101→/**
102→ * Build an OAuth 2.1 authorization URL with PKCE S256 and resource parameter (RFC 8707).
103→ * Pure function -- all inputs explicit, no side effects.
104→ */
105→export function buildAuthorizationUrl(params: AuthorizationParams): string;
106→export function buildAuthorizationUrl(
107→  provider: CredentialProviderRecord,
108→  redirectUri: string,
109→  state: string,
110→): string;
111→export function buildAuthorizationUrl(
112→  paramsOrProvider: AuthorizationParams | CredentialProviderRecord,
113→  redirectUri?: string,
114→  state?: string,
115→): string {
116→  // Overload: AuthorizationParams (new PKCE-aware version)
117→  if ("authorizationEndpoint" in paramsOrProvider) {
118→    const params = paramsOrProvider;
119→    const url = new URL(params.authorizationEndpoint);
120→    url.searchParams.set("response_type", "code");
121→    url.searchParams.set("client_id", params.clientId);
122→    url.searchParams.set("redirect_uri", params.redirectUri);
123→    url.searchParams.set("code_challenge", params.codeChallenge);
124→    url.searchParams.set("code_challenge_method", "S256");
125→    url.searchParams.set("state", params.state);
126→    url.searchParams.set("resource", params.resource);
127→    if (params.scope) {
128→      url.searchParams.set("scope", params.scope);
129→    }
130→    return url.toString();
131→  }
132→
133→  // Overload: legacy provider-based version
134→  const provider = paramsOrProvider;
135→  if (!provider.authorization_url) {
136→    throw new Error("Provider missing authorization_url for OAuth2 flow");
137→  }
138→  if (!provider.client_id) {
139→    throw new Error("Provider missing client_id for OAuth2 flow");
140→  }
141→
142→  const url = new URL(provider.authorization_url);
143→  url.searchParams.set("client_id", provider.client_id);
144→  url.searchParams.set("redirect_uri", redirectUri!);
145→  url.searchParams.set("response_type", "code");
146→  url.searchParams.set("state", state!);
147→
148→  if (provider.scopes && provider.scopes.length > 0) {
149→    url.searchParams.set("scope", provider.scopes.join(" "));
150→  }
151→
152→  return url.toString();
153→}
154→
155→// ---------------------------------------------------------------------------
156→// Token Exchange
157→// ---------------------------------------------------------------------------
158→
159→export type TokenExchangeResult = {
160→  access_token: string;
161→  refresh_token?: string;
162→  expires_in?: number;
163→  scope?: string;
164→};
165→
166→/**
167→ * Exchange an authorization code for tokens at the provider's token endpoint.
168→ * Sends client_id and client_secret via POST body (application/x-www-form-urlencoded).
169→ */
170→export async function exchangeCodeForTokens(
171→  provider: CredentialProviderRecord,
172→  code: string,
173→  redirectUri: string,
174→  clientSecret: string,
175→): Promise<TokenExchangeResult> {
176→  if (!provider.token_url) {
177→    throw new Error("Provider missing token_url for OAuth2 token exchange");
178→  }
179→  if (!provider.client_id) {
180→    throw new Error("Provider missing client_id for OAuth2 token exchange");
181→  }
182→
183→  const body = new URLSearchParams({
184→    grant_type: "authorization_code",
185→    code,
186→    redirect_uri: redirectUri,
187→    client_id: provider.client_id,
188→    client_secret: clientSecret,
189→  });
190→
191→  const response = await fetch(provider.token_url, {
192→    method: "POST",
193→    headers: { "Content-Type": "application/x-www-form-urlencoded", Accept: "application/json" },
194→    body: body.toString(),
195→  });
196→
197→  if (!response.ok) {
198→    const text = await response.text();
199→    throw new Error(`Token exchange failed (${response.status}): ${text}`);
200→  }
201→
202→  const data = await response.json() as TokenExchangeResult;
203→  return data;
204→}
205→
206→// ---------------------------------------------------------------------------
207→// PKCE Token Request Builder (Pure)
208→// ---------------------------------------------------------------------------
209→
210→/**
211→ * Build a token exchange request for authorization_code grant with PKCE.
212→ * Pure function -- produces { url, body, headers } without performing IO.
213→ */
214→export function buildTokenRequest(params: TokenExchangeParams): {
215→  url: string;
216→  body: URLSearchParams;
217→  headers: Record<string, string>;
218→} {
219→  const body = new URLSearchParams({
220→    grant_type: "authorization_code",
221→    code: params.code,
222→    redirect_uri: params.redirectUri,
223→    code_verifier: params.codeVerifier,
224→    client_id: params.clientId,
225→  });
226→
227→  return {
228→    url: params.tokenEndpoint,
229→    body,
230→    headers: {
231→      "Content-Type": "application/x-www-form-urlencoded",
232→      "Accept": "application/json",
233→    },
234→  };
235→}
236→
237→// ---------------------------------------------------------------------------
238→// Token Refresh (Effect)
239→// ---------------------------------------------------------------------------
240→
241→type FetchFn = typeof globalThis.fetch;
242→
243→/**
244→ * Refresh parameters for grant_type=refresh_token.
245→ */
246→export type RefreshTokenParams = {
247→  tokenEndpoint: string;
248→  refreshToken: string;
249→  clientId?: string;
250→  clientSecret?: string;
251→};
252→
253→/**
254→ * Refresh an access token using grant_type=refresh_token.
255→ * Effect function -- fetch is injectable for testability.
256→ */
257→export async function refreshAccessToken(
258→  params: RefreshTokenParams,
259→  fetchFn: FetchFn = globalThis.fetch,
260→): Promise<TokenResult> {
261→  const body = new URLSearchParams({
262→    grant_type: "refresh_token",
263→    refresh_token: params.refreshToken,
264→  });
265→
266→  if (params.clientId) {
267→    body.set("client_id", params.clientId);
268→  }
269→  if (params.clientSecret) {
270→    body.set("client_secret", params.clientSecret);
271→  }
272→
273→  const response = await fetchFn(params.tokenEndpoint, {
274→    method: "POST",
275→    headers: {
276→      "Content-Type": "application/x-www-form-urlencoded",
277→      "Accept": "application/json",
278→    },
279→    body: body.toString(),
280→  });
281→
282→  if (!response.ok) {
283→    const text = await response.text();
284→    throw new Error(`Token refresh failed (${response.status}): ${text}`);
285→  }
286→
287→  return (await response.json()) as TokenResult;
288→}
289→
290→// ---------------------------------------------------------------------------
291→// Dynamic Client Registration (RFC 7591)
292→// ---------------------------------------------------------------------------
293→
294→/**
295→ * Client metadata sent to the registration_endpoint.
296→ */
297→export type ClientRegistrationMetadata = {
298→  client_name: string;
299→  redirect_uris: string[];
300→  grant_types: string[];
301→  response_types: string[];
302→  token_endpoint_auth_method: string;
303→};
304→
305→/**
306→ * Response from the registration_endpoint.
307→ */
308→export type ClientRegistrationResult = {
309→  client_id: string;
310→  client_secret?: string;
311→  client_name?: string;
312→  redirect_uris?: string[];
313→};
314→
315→/**
316→ * Register Brain as an OAuth client via dynamic client registration (RFC 7591).
317→ * Effect function -- fetch is injectable for testability.
318→ */
319→export async function registerDynamicClient(
320→  registrationEndpoint: string,
321→  metadata: ClientRegistrationMetadata,
322→  fetchFn: FetchFn = globalThis.fetch,
323→): Promise<ClientRegistrationResult> {
324→  const response = await fetchFn(registrationEndpoint, {
325→    method: "POST",
326→    headers: {
327→      "Content-Type": "application/json",
328→      "Accept": "application/json",
329→    },
330→    body: JSON.stringify(metadata),
331→  });
332→
333→  if (!response.ok) {
334→    const text = await response.text();
335→    throw new Error(`Dynamic client registration failed (${response.status}): ${text}`);
336→  }
337→
338→  return (await response.json()) as ClientRegistrationResult;
339→}
340→
341→// ---------------------------------------------------------------------------
342→// PKCE Token Exchange (Effect)
343→// ---------------------------------------------------------------------------
344→
345→/**
346→ * Exchange an authorization code for tokens using PKCE at the token endpoint.
347→ * Effect function -- fetch is injectable for testability.
348→ */
349→export async function exchangeCode(
350→  params: TokenExchangeParams,
351→  fetchFn: FetchFn = globalThis.fetch,
352→): Promise<TokenResult> {
353→  const request = buildTokenRequest(params);
354→
355→  const response = await fetchFn(request.url, {
356→    method: "POST",
357→    headers: request.headers,
358→    body: request.body.toString(),
359→  });
360→
361→  if (!response.ok) {
362→    const text = await response.text();
363→    throw new Error(`Token exchange failed (${response.status}): ${text}`);
364→  }
365→
366→  return (await response.json()) as TokenResult;
367→}
