  1→/**
  2→ * HTTP routes for MCP server management.
  3→ *
  4→ * POST   /api/workspaces/:wsId/mcp-servers              (register server)
  5→ * GET    /api/workspaces/:wsId/mcp-servers               (list servers)
  6→ * GET    /api/workspaces/:wsId/mcp-servers/:serverId     (server detail)
  7→ * DELETE /api/workspaces/:wsId/mcp-servers/:serverId     (remove server)
  8→ * POST   /api/workspaces/:wsId/mcp-servers/:serverId/discover  (dry-run discovery)
  9→ * POST   /api/workspaces/:wsId/mcp-servers/:serverId/sync      (apply sync)
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import { HttpError } from "../http/errors";
 13→import { jsonError, jsonResponse } from "../http/response";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 16→import {
 17→  validateMcpServerUrl,
 18→  validateMcpServerTransport,
 19→} from "./server-validation";
 20→import {
 21→  serverNameExists,
 22→  createMcpServer,
 23→  listMcpServers,
 24→  getMcpServerById,
 25→  deleteMcpServer,
 26→  updateMcpServerHeaders,
 27→  clearMcpServerHeaders,
 28→  updateMcpServerProvider,
 29→  storePendingOAuthState,
 30→  findServerByPendingState,
 31→  clearPendingOAuthState,
 32→  updateMcpServerOAuthAccount,
 33→  findWorkspaceOwnerIdentity,
 34→  getMcpServerAuthStatus,
 35→  type McpServerRow,
 36→} from "./server-queries";
 37→import {
 38→  getProviderById,
 39→  createProvider,
 40→  findProviderByDiscoverySource,
 41→  createConnectedAccount,
 42→  updateProviderClientRegistration,
 43→} from "./queries";
 44→import { encryptSecret } from "./encryption";
 45→import { discoverTools } from "./discovery";
 46→import { discoverAuth } from "./auth-discovery";
 47→import { generatePkce, buildAuthorizationUrl, exchangeCode, registerDynamicClient } from "./oauth-flow";
 48→import type { McpServerRecord, EncryptedHeaderEntry, DiscoverAuthResponse, AuthorizationParams } from "./types";
 49→import { encryptHeaders, validateHeaders } from "./static-headers";
 50→import { log } from "../telemetry/logger";
 51→
 52→const VALID_AUTH_MODES: ReadonlySet<string> = new Set(["none", "static_headers", "oauth", "provider"]);
 53→
 54→// ---------------------------------------------------------------------------
 55→// Response mapping -- DB record to API shape
 56→// ---------------------------------------------------------------------------
 57→
 58→type McpServerResponse = {
 59→  id: string;
 60→  name: string;
 61→  url: string;
 62→  transport: string;
 63→  auth_mode: string;
 64→  has_static_headers: boolean;
 65→  tool_count: number;
 66→  last_status?: string;
 67→  last_error?: string;
 68→  last_discovery?: string;
 69→  provider_id?: string;
 70→  provider_name?: string;
 71→  created_at: string;
 72→};
 73→
 74→function toMcpServerResponse(
 75→  row: McpServerRow,
 76→  providerName?: string,
 77→): McpServerResponse {
 78→  const response: McpServerResponse = {
 79→    id: row.id.id as string,
 80→    name: row.name,
 81→    url: row.url,
 82→    transport: row.transport,
 83→    auth_mode: row.auth_mode ?? "none",
 84→    has_static_headers: Array.isArray(row.static_headers) && row.static_headers.length > 0,
 85→    tool_count: row.tool_count,
 86→    created_at: row.created_at instanceof Date
 87→      ? row.created_at.toISOString()
 88→      : String(row.created_at),
 89→  };
 90→
 91→  if (row.last_status) {
 92→    response.last_status = row.last_status;
 93→  }
 94→  if (row.last_error) {
 95→    response.last_error = row.last_error;
 96→  }
 97→  if (row.last_discovery) {
 98→    response.last_discovery = row.last_discovery instanceof Date
 99→      ? row.last_discovery.toISOString()
100→      : String(row.last_discovery);
101→  }
102→  if (row.provider) {
103→    response.provider_id = row.provider.id as string;
104→    if (providerName) {
105→      response.provider_name = providerName;
106→    }
107→  }
108→
109→  return response;
110→}
111→
112→// ---------------------------------------------------------------------------
113→// Input type
114→// ---------------------------------------------------------------------------
115→
116→type CreateMcpServerInput = {
117→  name?: string;
118→  url?: string;
119→  transport?: string;
120→  provider_id?: string;
121→  auth_mode?: string;
122→  static_headers?: Array<{ name?: string; value?: string }>;
123→};
124→
125→// ---------------------------------------------------------------------------
126→// Route handlers
127→// ---------------------------------------------------------------------------
128→
129→export function createServerRouteHandlers(deps: ServerDependencies) {
130→  async function handleCreateServer(
131→    workspaceId: string,
132→    request: Request,
133→  ): Promise<Response> {
134→    let workspaceRecord: RecordId<"workspace", string>;
135→    try {
136→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
137→    } catch (error) {
138→      if (error instanceof HttpError) {
139→        return jsonError(error.message, error.status);
140→      }
141→      log.error("mcp-server.create", "Failed to resolve workspace", error, { workspaceId });
142→      return jsonError("internal error", 500);
143→    }
144→
145→    let body: CreateMcpServerInput;
146→    try {
147→      body = await request.json() as CreateMcpServerInput;
148→    } catch {
149→      return jsonError("invalid JSON body", 400);
150→    }
151→
152→    // Validate name
153→    if (!body.name || typeof body.name !== "string" || body.name.trim().length === 0) {
154→      return jsonError("name is required", 400);
155→    }
156→
157→    // Validate URL
158→    const urlString = body.url ?? "";
159→    const urlValidation = validateMcpServerUrl(urlString);
160→    if (!urlValidation.ok) {
161→      return jsonError(urlValidation.error, 400);
162→    }
163→
164→    // Validate transport (default to streamable-http)
165→    const transport = body.transport ?? "streamable-http";
166→    const transportValidation = validateMcpServerTransport(transport);
167→    if (!transportValidation.ok) {
168→      return jsonError(transportValidation.error, 400);
169→    }
170→
171→    // Validate provider link if specified
172→    let providerRecord: RecordId<"credential_provider", string> | undefined;
173→    let providerName: string | undefined;
174→    if (body.provider_id) {
175→      const provider = await getProviderById(deps.surreal, body.provider_id);
176→      if (!provider) {
177→        return jsonError("Credential provider not found", 404);
178→      }
179→      providerRecord = new RecordId("credential_provider", body.provider_id);
180→      providerName = (provider as unknown as { display_name?: string }).display_name;
181→    }
182→
183→    // Validate auth_mode
184→    const authMode = body.auth_mode ?? "none";
185→    if (!VALID_AUTH_MODES.has(authMode)) {
186→      return jsonError(`Invalid auth_mode: must be one of none, static_headers, oauth, provider`, 400);
187→    }
188→
189→    // Encrypt static headers if provided
190→    let encryptedHeaders: EncryptedHeaderEntry[] | undefined;
191→    if (authMode === "static_headers") {
192→      const encryptionKey = deps.config.toolEncryptionKey;
193→      if (!encryptionKey) {
194→        log.error("mcp-server.create", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
195→        return jsonError("Server encryption not configured", 500);
196→      }
197→      if (!Array.isArray(body.static_headers) || body.static_headers.length === 0) {
198→        return jsonError("static_headers required when auth_mode is static_headers", 400);
199→      }
200→      // Validate header entries before encryption
201→      for (const header of body.static_headers) {
202→        if (!header.name || !header.value) {
203→          return jsonError("Each static header must have name and value", 400);
204→        }
205→      }
206→      const headerValidation = validateHeaders(
207→        body.static_headers as Array<{ name: string; value: string }>,
208→      );
209→      if (!headerValidation.ok) {
210→        return jsonError(headerValidation.error, 400);
211→      }
212→      encryptedHeaders = encryptHeaders(
213→        body.static_headers as Array<{ name: string; value: string }>,
214→        encryptionKey,
215→      );
216→    }
217→
218→    // Check duplicate name
219→    const duplicate = await serverNameExists(deps.surreal, workspaceRecord, body.name);
220→    if (duplicate) {
221→      return jsonError(`MCP server "${body.name}" already exists in this workspace`, 409);
222→    }
223→
224→    // Create server
225→    const row = await createMcpServer(deps.surreal, workspaceRecord, {
226→      name: body.name,
227→      url: urlString,
228→      transport,
229→      authMode,
230→      staticHeaders: encryptedHeaders,
231→      providerRecord,
232→    });
233→
234→    const response = toMcpServerResponse(row, providerName) as Record<string, unknown>;
235→
236→    // OAuth auto-discovery: probe the MCP server for OAuth metadata, create/find
237→    // provider, optionally register as dynamic client, then generate the
238→    // authorization URL so the frontend can redirect immediately.
239→    if (authMode === "oauth") {
240→      const authUrl = await autoDiscoverAndAuthorize(row, workspaceRecord);
241→      if (authUrl) {
242→        response.authorization_url = authUrl;
243→      }
244→    }
245→
246→    return jsonResponse(response, 201);
247→  }
248→
249→  /**
250→   * Auto-discover OAuth metadata from an MCP server and generate an authorization URL.
251→   * Returns the authorization URL if successful, undefined otherwise.
252→   */
253→  async function autoDiscoverAndAuthorize(
254→    server: McpServerRow,
255→    workspaceRecord: RecordId<"workspace", string>,
256→  ): Promise<string | undefined> {
257→    try {
258→      const config = await discoverAuth(server.url);
259→      if (!config) return undefined;
260→
261→      // Find or create credential_provider
262→      const existingProvider = await findProviderByDiscoverySource(
263→        deps.surreal,
264→        workspaceRecord,
265→        server.url,
266→      );
267→      const providerRecord = existingProvider ?? await createProvider(
268→        deps.surreal,
269→        workspaceRecord,
270→        {
271→          name: new URL(config.authServerUrl).hostname,
272→          display_name: new URL(config.authServerUrl).hostname,
273→          auth_method: "oauth2",
274→          authorization_url: config.authorizationEndpoint,
275→          token_url: config.tokenEndpoint,
276→          discovery_source: server.url,
277→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
278→        },
279→      );
280→
281→      // Dynamic client registration (RFC 7591) — only for newly created providers
282→      if (config.registrationEndpoint && !existingProvider) {
283→        try {
284→          const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
285→          const registrationResult = await registerDynamicClient(
286→            config.registrationEndpoint,
287→            {
288→              client_name: "Brain",
289→              redirect_uris: [redirectUri],
290→              grant_types: ["authorization_code"],
291→              response_types: ["code"],
292→              token_endpoint_auth_method: "none",
293→            },
294→          );
295→
296→          const encryptionKey = deps.config.toolEncryptionKey;
297→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
298→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
299→            : undefined;
300→
301→          await updateProviderClientRegistration(
302→            deps.surreal,
303→            providerRecord.id,
304→            registrationResult.client_id,
305→            clientSecretEncrypted,
306→          );
307→        } catch (regError) {
308→          log.error("mcp-server.auto-discover", "Dynamic client registration failed", regError, {
309→            serverId: server.id.id as string,
310→          });
311→        }
312→      }
313→
314→      // Link mcp_server to provider
315→      await updateMcpServerProvider(deps.surreal, server.id, providerRecord.id);
316→
317→      // Generate PKCE + authorization URL
318→      const pkce = await generatePkce();
319→      const state = crypto.randomUUID();
320→
321→      await storePendingOAuthState(deps.surreal, server.id, pkce.codeVerifier, state);
322→
323→      const clientId = (providerRecord as unknown as { client_id?: string }).client_id
324→        ?? deps.config.baseUrl;
325→      const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
326→      const scopes = (providerRecord as unknown as { scopes?: string[] }).scopes;
327→
328→      const authorizationParams: AuthorizationParams = {
329→        authorizationEndpoint: config.authorizationEndpoint,
330→        clientId,
331→        redirectUri,
332→        codeChallenge: pkce.codeChallenge,
333→        state,
334→        resource: server.url,
335→        scope: scopes?.join(" "),
336→      };
337→
338→      return buildAuthorizationUrl(authorizationParams);
339→    } catch (error) {
340→      log.error("mcp-server.auto-discover", "OAuth auto-discovery failed", error, {
341→        serverId: server.id.id as string,
342→      });
343→      return undefined;
344→    }
345→  }
