592→  async function handleDiscoverAuth(
593→    workspaceId: string,
594→    serverId: string,
595→    _request: Request,
596→  ): Promise<Response> {
597→    const resolved = await resolveServer(workspaceId, serverId);
598→    if ("error" in resolved) return resolved.error;
599→
600→    const server = resolved.server;
601→
602→    try {
603→      const config = await discoverAuth(server.url);
604→
605→      if (!config) {
606→        const response: DiscoverAuthResponse = {
607→          discovered: false,
608→          error: "No OAuth metadata found at the MCP server URL",
609→        };
610→        return jsonResponse(response, 200);
611→      }
612→
613→      // Find or create credential_provider from discovery (dedup by discovery_source)
614→      const authServerHostname = new URL(config.authServerUrl).hostname;
615→      const existingProvider = await findProviderByDiscoverySource(
616→        deps.surreal,
617→        server.workspace,
618→        server.url,
619→      );
620→      const providerRecord = existingProvider ?? await createProvider(
621→        deps.surreal,
622→        server.workspace,
623→        {
624→          name: authServerHostname,
625→          display_name: authServerHostname,
626→          auth_method: "oauth2",
627→          authorization_url: config.authorizationEndpoint,
628→          token_url: config.tokenEndpoint,
629→          discovery_source: server.url,
630→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
631→        },
632→      );
633→
634→      // Dynamic client registration (RFC 7591) — only for newly created providers
635→      if (config.registrationEndpoint && !existingProvider) {
636→        try {
637→          const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
638→
639→          const registrationResult = await registerDynamicClient(
640→            config.registrationEndpoint,
641→            {
642→              client_name: "Brain",
643→              redirect_uris: [redirectUri],
644→              grant_types: ["authorization_code"],
645→              response_types: ["code"],
646→              token_endpoint_auth_method: "none",
647→            },
648→          );
649→
650→          const encryptionKey = deps.config.toolEncryptionKey;
651→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
652→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
653→            : undefined;
654→
655→          await updateProviderClientRegistration(
656→            deps.surreal,
657→            providerRecord.id,
658→            registrationResult.client_id,
659→            clientSecretEncrypted,
660→          );
661→        } catch (regError) {
662→          log.error("mcp-server.discover-auth", "Dynamic client registration failed", regError, { serverId: server.id.id as string });
663→          // Non-fatal: proceed without dynamic registration
664→        }
665→      }
666→
667→      // Link mcp_server to the new provider
668→      await updateMcpServerProvider(
669→        deps.surreal,
670→        server.id,
671→        providerRecord.id,
672→      );
673→
674→      const response: DiscoverAuthResponse = {
675→        discovered: true,
676→        auth_server: config.authServerUrl,
677→        authorization_endpoint: config.authorizationEndpoint,
678→        token_endpoint: config.tokenEndpoint,
679→        scopes_supported: config.scopesSupported,
680→        supports_dynamic_registration: config.registrationEndpoint !== undefined,
681→        provider_id: providerRecord.id.id as string,
682→      };
683→
684→      return jsonResponse(response, 200);
685→    } catch (error) {
686→      log.error("mcp-server.discover-auth", "OAuth discovery failed", error, { serverId });
687→      return jsonError(
688→        `OAuth discovery failed: ${error instanceof Error ? error.message : "unknown error"}`,
689→        502,
690→      );
691→    }
692→  }
