694→  async function handleAuthorize(
695→    workspaceId: string,
696→    serverId: string,
697→    _request: Request,
698→  ): Promise<Response> {
699→    const resolved = await resolveServer(workspaceId, serverId);
700→    if ("error" in resolved) return resolved.error;
701→
702→    const server = resolved.server;
703→
704→    // Server must have a linked credential_provider (from discover-auth)
705→    if (!server.provider) {
706→      return jsonError("MCP server has no linked credential provider. Run discover-auth first.", 400);
707→    }
708→
709→    const provider = await getProviderById(deps.surreal, server.provider.id as string);
710→    if (!provider) {
711→      return jsonError("Linked credential provider not found", 404);
712→    }
713→
714→    const providerRecord = provider as unknown as {
715→      authorization_url?: string;
716→      client_id?: string;
717→      scopes?: string[];
718→    };
719→
720→    if (!providerRecord.authorization_url) {
721→      return jsonError("Provider missing authorization_url", 400);
722→    }
723→
724→    // Generate PKCE pair and random state
725→    const pkce = await generatePkce();
726→    const state = crypto.randomUUID();
727→
728→    // Store pending state on the mcp_server record (no module-level singletons)
729→    await storePendingOAuthState(
730→      deps.surreal,
731→      server.id,
732→      pkce.codeVerifier,
733→      state,
734→    );
735→
736→    // Build the redirect_uri (Brain's OAuth callback)
737→    const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
738→
739→    // Use client_id from provider, or fall back to Brain's base URL
740→    const clientId = providerRecord.client_id ?? deps.config.baseUrl;
741→
742→    // Build authorization URL with PKCE and resource parameter
743→    const authorizationParams: AuthorizationParams = {
744→      authorizationEndpoint: providerRecord.authorization_url,
745→      clientId,
746→      redirectUri,
747→      codeChallenge: pkce.codeChallenge,
748→      state,
749→      resource: server.url,
750→      scope: providerRecord.scopes?.join(" "),
751→    };
752→
753→    const redirectUrl = buildAuthorizationUrl(authorizationParams);
754→
755→    return jsonResponse({ redirect_url: redirectUrl, state }, 200);
756→  }
757→
758→  async function handleOAuthCallback(
759→    workspaceId: string,
760→    request: Request,
761→  ): Promise<Response> {
762→    let workspaceRecord: RecordId<"workspace", string>;
763→    try {
764→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
765→    } catch (error) {
766→      if (error instanceof HttpError) {
767→        return jsonError(error.message, error.status);
768→      }
769→      log.error("mcp-server.oauth-callback", "Failed to resolve workspace", error, { workspaceId });
770→      return jsonError("internal error", 500);
771→    }
772→
773→    // Parse code + state from query params (GET redirect from OAuth provider)
774→    // or request body (POST from frontend) for backwards compat
775→    let code: string | undefined;
776→    let state: string | undefined;
777→
778→    const url = new URL(request.url);
779→    if (url.searchParams.has("code")) {
780→      code = url.searchParams.get("code") ?? undefined;
781→      state = url.searchParams.get("state") ?? undefined;
782→    } else {
783→      try {
784→        const body = await request.json() as { code?: string; state?: string };
785→        code = body.code;
786→        state = body.state;
787→      } catch {
788→        return jsonError("invalid request", 400);
789→      }
790→    }
791→
792→    if (!code || typeof code !== "string") {
793→      return jsonError("code is required", 400);
794→    }
795→    if (!state || typeof state !== "string") {
796→      return jsonError("state is required", 400);
797→    }
798→
799→    // Find the mcp_server that has this pending state
800→    const server = await findServerByPendingState(deps.surreal, workspaceRecord, state);
801→    if (!server) {
802→      return jsonError("No pending authorization found for the provided state", 404);
803→    }
804→
805→    if (!server.pending_pkce_verifier) {
806→      return jsonError("Server missing PKCE code_verifier", 400);
807→    }
808→
809→    // Load the linked credential_provider for token_endpoint
810→    if (!server.provider) {
811→      return jsonError("Server has no linked credential provider", 400);
812→    }
813→
814→    const provider = await getProviderById(deps.surreal, server.provider.id as string);
815→    if (!provider) {
816→      return jsonError("Linked credential provider not found", 404);
817→    }
818→
819→    const providerRecord = provider as unknown as {
820→      token_url?: string;
821→      client_id?: string;
822→    };
823→
824→    if (!providerRecord.token_url) {
825→      return jsonError("Provider missing token_url", 400);
826→    }
827→
828→    // Build redirect_uri (must match the one used during authorize)
829→    const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
830→
831→    // Use client_id from provider, or fall back to Brain's base URL
832→    const clientId = providerRecord.client_id ?? deps.config.baseUrl;
833→
834→    try {
835→      // Exchange the authorization code for tokens using PKCE
836→      const tokenResult = await exchangeCode({
837→        tokenEndpoint: providerRecord.token_url,
838→        code,
839→        redirectUri,
840→        codeVerifier: server.pending_pkce_verifier,
841→        clientId,
842→      });
843→
844→      // Encrypt tokens before storage
845→      const encryptionKey = deps.config.toolEncryptionKey;
846→      if (encryptionKey) {
847→        // Find workspace owner identity for the connected_account
848→        const ownerIdentity = await findWorkspaceOwnerIdentity(deps.surreal, workspaceRecord);
849→        if (ownerIdentity) {
850→          const accountContent: Record<string, unknown> = {
851→            identity: ownerIdentity,
852→            provider: server.provider,
853→            workspace: workspaceRecord,
854→            status: "active",
855→            access_token_encrypted: encryptSecret(tokenResult.access_token, encryptionKey),
856→          };
857→
858→          if (tokenResult.refresh_token) {
859→            accountContent.refresh_token_encrypted = encryptSecret(tokenResult.refresh_token, encryptionKey);
860→          }
861→
862→          if (tokenResult.expires_in) {
863→            accountContent.token_expires_at = new Date(Date.now() + tokenResult.expires_in * 1000);
864→          }
865→
866→          if (tokenResult.scope) {
867→            accountContent.scopes = tokenResult.scope.split(" ");
868→          }
869→
870→          const account = await createConnectedAccount(deps.surreal, accountContent);
871→
872→          // Link mcp_server to the new connected_account
873→          await updateMcpServerOAuthAccount(deps.surreal, server.id, account.id);
874→        }
875→      }
876→
877→      // Clear pending PKCE state from the server record
878→      await clearPendingOAuthState(deps.surreal, server.id);
879→
880→      // GET = browser redirect from OAuth provider → redirect back to UI
881→      // POST = programmatic call → return JSON
882→      if (request.method === "GET") {
883→        return Response.redirect(
884→          `${deps.config.baseUrl}/tool-registry?tab=servers&oauth=success`,
885→          302,
886→        );
887→      }
888→      return jsonResponse(tokenResult, 200);
889→    } catch (error) {
890→      log.error("mcp-server.oauth-callback", "Token exchange failed", error, { workspaceId });
891→      if (request.method === "GET") {
892→        return Response.redirect(
893→          `${deps.config.baseUrl}/tool-registry?tab=servers&oauth=error`,
894→          302,
895→        );
896→      }
897→      return jsonError(
898→        `Token exchange failed: ${error instanceof Error ? error.message : "unknown error"}`,
899→        502,
900→      );
901→    }
902→  }
