  1→/**
  2→ * OAuth 2.1 Auth Discovery (RFC 9728 + RFC 8414)
  3→ *
  4→ * Pure core: parsing + URL derivation functions (no IO).
  5→ * Effect shell: discoverAuth() performs HTTP fetches via injectable fetchFn.
  6→ *
  7→ * Flow:
  8→ *   1. Fetch /.well-known/oauth-protected-resource from MCP server origin
  9→ *   2. Parse Protected Resource Metadata, extract authorization_servers[0]
 10→ *   3. Derive well-known endpoints for the auth server
 11→ *   4. Try each endpoint until one succeeds
 12→ *   5. Return DiscoveredAuthConfig or undefined
 13→ */
 14→import type {
 15→  ProtectedResourceMetadata,
 16→  AuthServerMetadata,
 17→  DiscoveredAuthConfig,
 18→} from "./types";
 19→import { log } from "../telemetry/logger";
 20→
 21→// ---------------------------------------------------------------------------
 22→// Result type (pure, no exceptions)
 23→// ---------------------------------------------------------------------------
 24→
 25→type Result<T> =
 26→  | { ok: true; value: T }
 27→  | { ok: false; error: string };
 28→
 29→// ---------------------------------------------------------------------------
 30→// Pure core: parsing functions
 31→// ---------------------------------------------------------------------------
 32→
 33→/**
 34→ * Parse and validate Protected Resource Metadata (RFC 9728).
 35→ */
 36→export function parseProtectedResourceMetadata(
 37→  json: unknown,
 38→): Result<ProtectedResourceMetadata> {
 39→  if (typeof json !== "object" || json === null || Array.isArray(json)) {
 40→    return { ok: false, error: "Protected Resource Metadata must be a JSON object" };
 41→  }
 42→
 43→  const obj = json as Record<string, unknown>;
 44→
 45→  if (typeof obj.resource !== "string" || obj.resource.length === 0) {
 46→    return { ok: false, error: "Missing or invalid 'resource' field" };
 47→  }
 48→
 49→  if (
 50→    !Array.isArray(obj.authorization_servers) ||
 51→    obj.authorization_servers.length === 0 ||
 52→    !obj.authorization_servers.every((s: unknown) => typeof s === "string")
 53→  ) {
 54→    return {
 55→      ok: false,
 56→      error: "Missing or empty 'authorization_servers' array",
 57→    };
 58→  }
 59→
 60→  const metadata: ProtectedResourceMetadata = {
 61→    resource: obj.resource,
 62→    authorization_servers: obj.authorization_servers as string[],
 63→  };
 64→
 65→  if (Array.isArray(obj.scopes_supported)) {
 66→    metadata.scopes_supported = obj.scopes_supported as string[];
 67→  }
 68→
 69→  if (Array.isArray(obj.bearer_methods_supported)) {
 70→    metadata.bearer_methods_supported = obj.bearer_methods_supported as string[];
 71→  }
 72→
 73→  return { ok: true, value: metadata };
 74→}
 75→
 76→/**
 77→ * Parse and validate Authorization Server Metadata (RFC 8414).
 78→ */
 79→export function parseAuthServerMetadata(
 80→  json: unknown,
 81→): Result<AuthServerMetadata> {
 82→  if (typeof json !== "object" || json === null || Array.isArray(json)) {
 83→    return { ok: false, error: "Auth Server Metadata must be a JSON object" };
 84→  }
 85→
 86→  const obj = json as Record<string, unknown>;
 87→
 88→  if (typeof obj.issuer !== "string" || obj.issuer.length === 0) {
 89→    return { ok: false, error: "Missing or invalid 'issuer' field" };
 90→  }
 91→
 92→  if (typeof obj.authorization_endpoint !== "string" || obj.authorization_endpoint.length === 0) {
 93→    return { ok: false, error: "Missing or invalid 'authorization_endpoint' field" };
 94→  }
 95→
 96→  if (typeof obj.token_endpoint !== "string" || obj.token_endpoint.length === 0) {
 97→    return { ok: false, error: "Missing or invalid 'token_endpoint' field" };
 98→  }
 99→
100→  const metadata: AuthServerMetadata = {
101→    issuer: obj.issuer,
102→    authorization_endpoint: obj.authorization_endpoint,
103→    token_endpoint: obj.token_endpoint,
104→    response_types_supported: Array.isArray(obj.response_types_supported)
105→      ? (obj.response_types_supported as string[])
106→      : ["code"],
107→  };
108→
109→  if (typeof obj.registration_endpoint === "string") {
110→    metadata.registration_endpoint = obj.registration_endpoint;
111→  }
112→
113→  if (Array.isArray(obj.scopes_supported)) {
114→    metadata.scopes_supported = obj.scopes_supported as string[];
115→  }
116→
117→  if (Array.isArray(obj.code_challenge_methods_supported)) {
118→    metadata.code_challenge_methods_supported = obj.code_challenge_methods_supported as string[];
119→  }
120→
121→  if (Array.isArray(obj.grant_types_supported)) {
122→    metadata.grant_types_supported = obj.grant_types_supported as string[];
123→  }
124→
125→  return { ok: true, value: metadata };
126→}
