128→// ---------------------------------------------------------------------------
129→// Pure core: URL derivation
130→// ---------------------------------------------------------------------------
131→
132→/**
133→ * Derive well-known discovery endpoint URLs for an authorization server (RFC 8414).
134→ *
135→ * For URLs without path: returns 2 endpoints.
136→ * For URLs with path: returns 3 endpoints (path-aware variants).
137→ */
138→export function deriveDiscoveryEndpoints(issuerUrl: string): string[] {
139→  const normalized = issuerUrl.replace(/\/+$/, "");
140→  const parsed = new URL(normalized);
141→  const origin = parsed.origin;
142→  const path = parsed.pathname === "/" ? "" : parsed.pathname;
143→
144→  if (path === "") {
145→    return [
146→      `${origin}/.well-known/oauth-authorization-server`,
147→      `${origin}/.well-known/openid-configuration`,
148→    ];
149→  }
150→
151→  return [
152→    `${origin}/.well-known/oauth-authorization-server${path}`,
153→    `${origin}/.well-known/openid-configuration${path}`,
154→    `${origin}${path}/.well-known/openid-configuration`,
155→  ];
156→}
157→
158→/**
159→ * Derive the Protected Resource Metadata URL from an MCP server URL.
160→ * Always uses the origin (strips path).
161→ */
162→export function deriveResourceMetadataUrl(serverUrl: string): string {
163→  const parsed = new URL(serverUrl);
164→  return `${parsed.origin}/.well-known/oauth-protected-resource`;
165→}
166→
167→/**
168→ * Select the first authorization server from the list.
169→ */
170→export function selectAuthorizationServer(servers: string[]): string | undefined {
171→  return servers[0];
172→}
173→
174→// ---------------------------------------------------------------------------
175→// Pure core: transform AuthServerMetadata -> DiscoveredAuthConfig
176→// ---------------------------------------------------------------------------
177→
178→function toDiscoveredAuthConfig(
179→  authServerUrl: string,
180→  authMetadata: AuthServerMetadata,
181→  resourceMetadata: ProtectedResourceMetadata,
182→): DiscoveredAuthConfig {
183→  const config: DiscoveredAuthConfig = {
184→    authServerUrl,
185→    authorizationEndpoint: authMetadata.authorization_endpoint,
186→    tokenEndpoint: authMetadata.token_endpoint,
187→    supportsS256: authMetadata.code_challenge_methods_supported?.includes("S256") ?? false,
188→    resourceUri: resourceMetadata.resource,
189→  };
190→
191→  if (authMetadata.registration_endpoint) {
192→    config.registrationEndpoint = authMetadata.registration_endpoint;
193→  }
194→
195→  // Merge scopes: prefer resource metadata scopes, fall back to auth server scopes
196→  const scopes = resourceMetadata.scopes_supported ?? authMetadata.scopes_supported;
197→  if (scopes && scopes.length > 0) {
198→    config.scopesSupported = scopes;
199→  }
200→
201→  return config;
202→}
203→
204→// ---------------------------------------------------------------------------
205→// Pure core: WWW-Authenticate header parsing
206→// ---------------------------------------------------------------------------
207→
208→/**
209→ * Parse WWW-Authenticate header to extract resource_metadata URL.
210→ *
211→ * Format: Bearer resource_metadata="https://..."
212→ * Per RFC 9728 section 5.1, the resource_metadata parameter in the
213→ * WWW-Authenticate header points to the Protected Resource Metadata URL.
214→ */
215→export function parseWwwAuthenticate(header: string): { resourceMetadataUrl?: string } {
216→  if (!header.startsWith("Bearer ")) {
217→    return { resourceMetadataUrl: undefined };
218→  }
219→
220→  const params = header.slice("Bearer ".length);
221→  const match = params.match(/resource_metadata="([^"]+)"/);
222→  if (match) {
223→    return { resourceMetadataUrl: match[1] };
224→  }
225→
226→  // Try unquoted value: resource_metadata=<url> (terminated by comma, space, or end)
227→  const unquotedMatch = params.match(/resource_metadata=([^,\s"]+)/);
228→  if (unquotedMatch) {
229→    return { resourceMetadataUrl: unquotedMatch[1] };
230→  }
231→
232→  return { resourceMetadataUrl: undefined };
233→}
234→
235→// ---------------------------------------------------------------------------
236→// Effect shell: HTTP discovery
237→// ---------------------------------------------------------------------------
238→
239→/**
240→ * Fetch JSON from a URL, returning undefined on failure.
241→ */
242→async function fetchJson(
243→  url: string,
244→  fetchFn: typeof fetch,
245→): Promise<unknown | undefined> {
246→  try {
247→    const response = await fetchFn(url, {
248→      headers: { Accept: "application/json" },
249→    });
250→    if (!response.ok) return undefined;
251→    return await response.json();
252→  } catch {
253→    return undefined;
254→  }
255→}
256→
257→/**
258→ * Fallback: request the MCP server to trigger a 401, then extract
259→ * the resource_metadata URL from the WWW-Authenticate header.
260→ * Returns the parsed resource metadata JSON, or undefined.
261→ */
262→async function fetchResourceMetadataViaWwwAuthenticate(
263→  serverUrl: string,
264→  fetchFn: typeof fetch,
265→): Promise<unknown | undefined> {
266→  try {
267→    const response = await fetchFn(serverUrl, {
268→      method: "POST",
269→      headers: {
270→        Accept: "application/json",
271→        "Content-Type": "application/json",
272→      },
273→    });
274→
275→    if (response.status !== 401) return undefined;
276→
277→    const wwwAuth = response.headers.get("WWW-Authenticate");
278→    if (!wwwAuth) return undefined;
279→
280→    const { resourceMetadataUrl } = parseWwwAuthenticate(wwwAuth);
281→    if (!resourceMetadataUrl) return undefined;
282→
283→    log.info("auth-discovery", "Found resource_metadata URL in WWW-Authenticate header", {
284→      resourceMetadataUrl,
285→    });
286→
287→    return await fetchJson(resourceMetadataUrl, fetchFn);
288→  } catch (error) {
289→    log.info("auth-discovery", "WWW-Authenticate fallback failed", {
290→      serverUrl,
291→      error: error instanceof Error ? error.message : String(error),
292→    });
293→    return undefined;
294→  }
295→}
296→
297→/**
298→ * Try well-known discovery endpoints for auth server metadata.
299→ * Returns the first valid AuthServerMetadata, or undefined.
300→ */
301→async function fetchAuthServerMetadata(
302→  authServerUrl: string,
303→  fetchFn: typeof fetch,
304→): Promise<AuthServerMetadata | undefined> {
305→  const discoveryEndpoints = deriveDiscoveryEndpoints(authServerUrl);
306→
307→  for (const endpoint of discoveryEndpoints) {
308→    const authJson = await fetchJson(endpoint, fetchFn);
309→    if (authJson === undefined) continue;
310→
311→    const authResult = parseAuthServerMetadata(authJson);
312→    if (authResult.ok) return authResult.value;
313→  }
314→
315→  log.info("auth-discovery", "No valid auth server metadata found at any well-known endpoint", {
316→    authServerUrl,
317→    endpointsTried: discoveryEndpoints,
318→  });
319→  return undefined;
320→}
321→
322→/**
323→ * Discover OAuth auth configuration from an MCP server URL.
324→ *
325→ * 1. Fetches Protected Resource Metadata from /.well-known/oauth-protected-resource
326→ * 2. If not found, falls back to requesting the MCP server (triggers 401)
327→ *    and parses resource_metadata URL from WWW-Authenticate header
328→ * 3. Extracts the first authorization server from resource metadata
329→ * 4. Tries well-known endpoints to fetch Auth Server Metadata
330→ * 5. Returns DiscoveredAuthConfig on success, undefined on failure
331→ *
332→ * fetchFn is injectable for testing.
333→ */
334→export async function discoverAuth(
335→  serverUrl: string,
336→  fetchFn: typeof fetch = fetch,
337→): Promise<DiscoveredAuthConfig | undefined> {
338→  // Step 1: Fetch Protected Resource Metadata (well-known path)
339→  const resourceMetadataUrl = deriveResourceMetadataUrl(serverUrl);
340→  let resourceJson = await fetchJson(resourceMetadataUrl, fetchFn);
341→
342→  // Step 1b: Fallback — trigger 401, parse WWW-Authenticate header
343→  if (resourceJson === undefined) {
344→    log.info("auth-discovery", "Protected Resource Metadata not available, trying WWW-Authenticate fallback", {
345→      url: resourceMetadataUrl,
346→    });
347→    resourceJson = await fetchResourceMetadataViaWwwAuthenticate(serverUrl, fetchFn);
348→  }
349→
350→  if (resourceJson === undefined) {
351→    log.info("auth-discovery", "No Protected Resource Metadata found via any method", {
352→      serverUrl,
353→    });
354→    return undefined;
355→  }
356→
357→  // Step 2: Parse resource metadata
358→  const resourceResult = parseProtectedResourceMetadata(resourceJson);
359→  if (!resourceResult.ok) {
360→    log.info("auth-discovery", "Invalid Protected Resource Metadata", {
361→      error: resourceResult.error,
362→    });
363→    return undefined;
364→  }
365→
366→  // Step 3: Select authorization server
367→  const authServerUrl = selectAuthorizationServer(resourceResult.value.authorization_servers);
368→  if (!authServerUrl) {
369→    log.info("auth-discovery", "No authorization servers found in metadata");
370→    return undefined;
371→  }
372→
373→  // Step 4: Fetch auth server metadata
374→  const authMetadata = await fetchAuthServerMetadata(authServerUrl, fetchFn);
375→  if (!authMetadata) return undefined;
376→
377→  return toDiscoveredAuthConfig(authServerUrl, authMetadata, resourceResult.value);
378→}
