249→  /**
250→   * Auto-discover OAuth metadata from an MCP server and generate an authorization URL.
251→   * Returns the authorization URL if successful, undefined otherwise.
252→   */
253→  async function autoDiscoverAndAuthorize(
254→    server: McpServerRow,
255→    workspaceRecord: RecordId<"workspace", string>,
256→  ): Promise<string | undefined> {
257→    try {
258→      const config = await discoverAuth(server.url);
259→      if (!config) return undefined;
260→
261→      // Find or create credential_provider
262→      const existingProvider = await findProviderByDiscoverySource(
263→        deps.surreal,
264→        workspaceRecord,
265→        server.url,
266→      );
267→      const providerRecord = existingProvider ?? await createProvider(
268→        deps.surreal,
269→        workspaceRecord,
270→        {
271→          name: new URL(config.authServerUrl).hostname,
272→          display_name: new URL(config.authServerUrl).hostname,
273→          auth_method: "oauth2",
274→          authorization_url: config.authorizationEndpoint,
275→          token_url: config.tokenEndpoint,
276→          discovery_source: server.url,
277→          ...(config.scopesSupported ? { scopes: config.scopesSupported } : {}),
278→        },
279→      );
280→
281→      // Dynamic client registration (RFC 7591) — only for newly created providers
282→      if (config.registrationEndpoint && !existingProvider) {
283→        try {
284→          const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
285→          const registrationResult = await registerDynamicClient(
286→            config.registrationEndpoint,
287→            {
288→              client_name: "Brain",
289→              redirect_uris: [redirectUri],
290→              grant_types: ["authorization_code"],
291→              response_types: ["code"],
292→              token_endpoint_auth_method: "none",
293→            },
294→          );
295→
296→          const encryptionKey = deps.config.toolEncryptionKey;
297→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
298→            ? encryptSecret(registrationResult.client_secret, encryptionKey)
299→            : undefined;
300→
301→          await updateProviderClientRegistration(
302→            deps.surreal,
303→            providerRecord.id,
304→            registrationResult.client_id,
305→            clientSecretEncrypted,
306→          );
307→        } catch (regError) {
308→          log.error("mcp-server.auto-discover", "Dynamic client registration failed", regError, {
309→            serverId: server.id.id as string,
310→          });
311→        }
312→      }
313→
314→      // Link mcp_server to provider
315→      await updateMcpServerProvider(deps.surreal, server.id, providerRecord.id);
316→
317→      // Generate PKCE + authorization URL
318→      const pkce = await generatePkce();
319→      const state = crypto.randomUUID();
320→
321→      await storePendingOAuthState(deps.surreal, server.id, pkce.codeVerifier, state);
322→
323→      const clientId = (providerRecord as unknown as { client_id?: string }).client_id
324→        ?? deps.config.baseUrl;
325→      const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
326→      const scopes = (providerRecord as unknown as { scopes?: string[] }).scopes;
327→
328→      const authorizationParams: AuthorizationParams = {
329→        authorizationEndpoint: config.authorizationEndpoint,
330→        clientId,
331→        redirectUri,
332→        codeChallenge: pkce.codeChallenge,
333→        state,
334→        resource: server.url,
335→        scope: scopes?.join(" "),
336→      };
337→
338→      return buildAuthorizationUrl(authorizationParams);
339→    } catch (error) {
340→      log.error("mcp-server.auto-discover", "OAuth auto-discovery failed", error, {
341→        serverId: server.id.id as string,
342→      });
343→      return undefined;
344→    }
345→  }
