511→    workspaceId: string,
512→    serverId: string,
513→    request: Request,
514→  ): Promise<Response> {
515→    let workspaceRecord: RecordId<"workspace", string>;
516→    try {
517→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
518→    } catch (error) {
519→      if (error instanceof HttpError) {
520→        return jsonError(error.message, error.status);
521→      }
522→      log.error("mcp-server.update-headers", "Failed to resolve workspace", error, { workspaceId });
523→      return jsonError("internal error", 500);
524→    }
525→
526→    let body: { headers?: Array<{ name?: string; value?: string }> };
527→    try {
528→      body = await request.json() as { headers?: Array<{ name?: string; value?: string }> };
529→    } catch {
530→      return jsonError("invalid JSON body", 400);
531→    }
532→
533→    if (!Array.isArray(body.headers)) {
534→      return jsonError("headers array is required", 400);
535→    }
536→
537→    const serverRecord = new RecordId("mcp_server", serverId);
538→
539→    // Empty headers array = clear all headers and reset auth_mode to "none"
540→    if (body.headers.length === 0) {
541→      const clearedRow = await clearMcpServerHeaders(
542→        deps.surreal,
543→        serverRecord,
544→        workspaceRecord,
545→      );
546→
547→      if (!clearedRow) {
548→        return jsonError("MCP server not found", 404);
549→      }
550→
551→      return jsonResponse(toMcpServerResponse(clearedRow), 200);
552→    }
553→
554→    // Validate each header entry
555→    for (const header of body.headers) {
556→      if (!header.name || !header.value) {
557→        return jsonError("Each header must have name and value", 400);
558→      }
559→    }
560→    const headerValidation = validateHeaders(
561→      body.headers as Array<{ name: string; value: string }>,
562→    );
563→    if (!headerValidation.ok) {
564→      return jsonError(headerValidation.error, 400);
565→    }
566→
567→    const encryptionKey = deps.config.toolEncryptionKey;
568→    if (!encryptionKey) {
569→      log.error("mcp-server.update-headers", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
570→      return jsonError("Server encryption not configured", 500);
571→    }
572→
573→    const encryptedHeaders = encryptHeaders(
574→      body.headers as Array<{ name: string; value: string }>,
575→      encryptionKey,
576→    );
577→
578→    const updatedRow = await updateMcpServerHeaders(
579→      deps.surreal,
580→      serverRecord,
581→      workspaceRecord,
582→      encryptedHeaders,
583→    );
584→
585→    if (!updatedRow) {
586→      return jsonError("MCP server not found", 404);
587→    }
588→
589→    return jsonResponse(toMcpServerResponse(updatedRow), 200);
590→  }
