634→      // Dynamic client registration (RFC 7591) — only for newly created providers
635→      if (config.registrationEndpoint && !existingProvider) {
636→        try {
637→          const redirectUri = `${deps.config.baseUrl}/oauth/callback`;
638→
639→          const registrationResult = await registerDynamicClient(
