645→              response_types: ["code"],
646→              token_endpoint_auth_method: "none",
647→            },
648→          );
649→
650→          const encryptionKey = deps.config.toolEncryptionKey;
651→          const clientSecretEncrypted = registrationResult.client_secret && encryptionKey
