  1→/**
  2→ * SurrealDB queries for mcp_server CRUD.
  3→ */
  4→import { RecordId, type Surreal } from "surrealdb";
  5→
  6→// ---------------------------------------------------------------------------
  7→// Row types
  8→// ---------------------------------------------------------------------------
  9→
 10→export type McpServerRow = {
 11→  readonly id: RecordId<"mcp_server", string>;
 12→  readonly name: string;
 13→  readonly url: string;
 14→  readonly transport: string;
 15→  readonly workspace: RecordId<"workspace", string>;
 16→  readonly auth_mode: string;
 17→  readonly provider?: RecordId<"credential_provider", string>;
 18→  readonly static_headers?: Array<{ name: string; value_encrypted: string }>;
 19→  readonly oauth_account?: RecordId<"connected_account", string>;
 20→  readonly last_status?: string;
 21→  readonly last_error?: string;
 22→  readonly server_info?: Record<string, unknown>;
 23→  readonly capabilities?: Record<string, unknown>;
 24→  readonly last_discovery?: Date | string;
 25→  readonly tool_count: number;
 26→  readonly created_at: Date | string;
 27→};
 28→
 29→// ---------------------------------------------------------------------------
 30→// Queries
 31→// ---------------------------------------------------------------------------
 32→
 33→/**
 34→ * Check if an mcp_server with the given name already exists in the workspace.
 35→ */
 36→export async function serverNameExists(
 37→  surreal: Surreal,
 38→  workspaceRecord: RecordId<"workspace", string>,
 39→  name: string,
 40→): Promise<boolean> {
 41→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
 42→    `SELECT id FROM mcp_server WHERE workspace = $ws AND name = $name LIMIT 1;`,
 43→    { ws: workspaceRecord, name },
 44→  );
 45→  return (results[0] ?? []).length > 0;
 46→}
 47→
 48→/**
 49→ * Create an mcp_server record.
 50→ */
 51→export async function createMcpServer(
 52→  surreal: Surreal,
 53→  workspaceRecord: RecordId<"workspace", string>,
 54→  input: {
 55→    name: string;
 56→    url: string;
 57→    transport: string;
 58→    authMode?: string;
 59→    staticHeaders?: Array<{ name: string; value_encrypted: string }>;
 60→    providerRecord?: RecordId<"credential_provider", string>;
 61→  },
 62→): Promise<McpServerRow> {
 63→  const serverId = crypto.randomUUID();
 64→  const serverRecord = new RecordId("mcp_server", serverId);
 65→
 66→  const content: Record<string, unknown> = {
 67→    name: input.name,
 68→    url: input.url,
 69→    transport: input.transport,
 70→    auth_mode: input.authMode ?? "none",
 71→    workspace: workspaceRecord,
 72→    tool_count: 0,
 73→    created_at: new Date(),
 74→  };
 75→
 76→  if (input.providerRecord) {
 77→    content.provider = input.providerRecord;
 78→  }
 79→
 80→  if (input.staticHeaders && input.staticHeaders.length > 0) {
 81→    content.static_headers = input.staticHeaders;
 82→  }
 83→
 84→  await surreal.query(`CREATE $server CONTENT $content;`, {
 85→    server: serverRecord,
 86→    content,
 87→  });
 88→
 89→  return {
 90→    id: serverRecord,
 91→    ...content,
 92→  } as unknown as McpServerRow;
 93→}
 94→
 95→/**
 96→ * List all mcp_servers in a workspace.
 97→ */
 98→export async function listMcpServers(
 99→  surreal: Surreal,
100→  workspaceRecord: RecordId<"workspace", string>,
101→): Promise<McpServerRow[]> {
102→  const results = await surreal.query<[McpServerRow[]]>(
103→    `SELECT * FROM mcp_server WHERE workspace = $ws ORDER BY created_at DESC;`,
104→    { ws: workspaceRecord },
105→  );
106→  return results[0] ?? [];
107→}
108→
109→/**
110→ * Get a single mcp_server by ID, scoped to workspace.
111→ */
112→export async function getMcpServerById(
113→  surreal: Surreal,
114→  serverRecord: RecordId<"mcp_server", string>,
115→  workspaceRecord: RecordId<"workspace", string>,
116→): Promise<McpServerRow | undefined> {
117→  const results = await surreal.query<[McpServerRow[]]>(
118→    `SELECT * FROM $server WHERE workspace = $ws;`,
119→    { server: serverRecord, ws: workspaceRecord },
120→  );
121→  return (results[0] ?? [])[0];
122→}
123→
124→/**
125→ * Replace all static headers on an mcp_server and set auth_mode to "static_headers".
126→ * Returns the updated row, or undefined if the server was not found in the workspace.
127→ */
128→export async function updateMcpServerHeaders(
129→  surreal: Surreal,
130→  serverRecord: RecordId<"mcp_server", string>,
131→  workspaceRecord: RecordId<"workspace", string>,
132→  encryptedHeaders: Array<{ name: string; value_encrypted: string }>,
133→): Promise<McpServerRow | undefined> {
134→  const existing = await getMcpServerById(surreal, serverRecord, workspaceRecord);
135→  if (!existing) {
136→    return undefined;
137→  }
138→
139→  await surreal.query(
140→    `UPDATE $server SET static_headers = $headers, auth_mode = "static_headers";`,
141→    { server: serverRecord, headers: encryptedHeaders },
142→  );
143→
144→  return getMcpServerById(surreal, serverRecord, workspaceRecord);
145→}
146→
147→/**
148→ * Clear all static headers on an mcp_server and reset auth_mode to "none".
149→ * Returns the updated row, or undefined if the server was not found in the workspace.
150→ */

