  1→/**
  2→ * Static header validation and encryption for MCP servers.
  3→ *
  4→ * Pure core:
  5→ *   validateHeaders  -- rejects restricted names, empty values, duplicates
  6→ *   buildHeaderMap   -- converts decrypted HeaderEntry[] to Record<string, string>
  7→ *
  8→ * Effect shell (delegates to encryption.ts):
  9→ *   encryptHeaders   -- encrypts each header value via AES-256-GCM
 10→ *   decryptHeaders   -- decrypts each encrypted header value
 11→ *
 12→ * ADR-066, ADR-068.
 13→ */
 14→import { encryptSecret, decryptSecret } from "./encryption";
 15→import type { HeaderEntry, EncryptedHeaderEntry } from "./types";
 16→
 17→// ---------------------------------------------------------------------------
 18→// Restricted header names (case-insensitive)
 19→// ---------------------------------------------------------------------------
 20→
 21→const RESTRICTED_HEADER_NAMES: ReadonlySet<string> = new Set([
 22→  "host",
 23→  "content-length",
 24→  "transfer-encoding",
 25→  "connection",
 26→]);
 27→
 28→// ---------------------------------------------------------------------------
 29→// Validation result type
 30→// ---------------------------------------------------------------------------
 31→
 32→export type ValidationResult =
 33→  | { ok: true }
 34→  | { ok: false; error: string };
 35→
 36→// ---------------------------------------------------------------------------
 37→// Pure core
 38→// ---------------------------------------------------------------------------
 39→
 40→/**
 41→ * Validate header entries before encryption.
 42→ *
 43→ * Rules:
 44→ *  - No restricted header names (Host, Content-Length, Transfer-Encoding, Connection)
 45→ *  - Non-empty name and value
 46→ *  - No duplicate names (case-insensitive)
 47→ */
 48→export function validateHeaders(headers: HeaderEntry[]): ValidationResult {
 49→  const seenNames = new Set<string>();
 50→
 51→  for (const header of headers) {
 52→    if (!header.name || header.name.trim().length === 0) {
 53→      return { ok: false, error: "Header name must not be empty" };
 54→    }
 55→
 56→    if (!header.value || header.value.length === 0) {
 57→      return { ok: false, error: `Header "${header.name}" must have a non-empty value` };
 58→    }
 59→
 60→    const normalizedName = header.name.toLowerCase();
 61→
 62→    if (RESTRICTED_HEADER_NAMES.has(normalizedName)) {
 63→      return { ok: false, error: `Restricted header name: ${header.name}` };
 64→    }
 65→
 66→    if (seenNames.has(normalizedName)) {
 67→      return { ok: false, error: `Duplicate header name (case-insensitive): ${header.name}` };
 68→    }
 69→
 70→    seenNames.add(normalizedName);
 71→  }
 72→
 73→  return { ok: true };
 74→}
 75→
 76→/**
 77→ * Convert decrypted header entries to a plain key-value map.
 78→ */
 79→export function buildHeaderMap(headers: HeaderEntry[]): Record<string, string> {
 80→  const map: Record<string, string> = {};
 81→  for (const header of headers) {
 82→    map[header.name] = header.value;
 83→  }
 84→  return map;
 85→}
 86→
 87→// ---------------------------------------------------------------------------
 88→// Effect shell
 89→// ---------------------------------------------------------------------------
 90→
 91→/**
 92→ * Encrypt each header value using AES-256-GCM.
 93→ * Header names are stored in plaintext; only values are encrypted.
 94→ */
 95→export function encryptHeaders(
 96→  headers: HeaderEntry[],
 97→  keyHex: string,
 98→): EncryptedHeaderEntry[] {
 99→  return headers.map((header) => ({
100→    name: header.name,
101→    value_encrypted: encryptSecret(header.value, keyHex),
102→  }));
103→}
104→
105→/**
106→ * Decrypt each encrypted header value back to plaintext.
107→ */
108→export function decryptHeaders(
109→  encrypted: EncryptedHeaderEntry[],
110→  keyHex: string,
111→): HeaderEntry[] {
112→  return encrypted.map((entry) => ({
113→    name: entry.name,
114→    value: decryptSecret(entry.value_encrypted, keyHex),
115→  }));
116→}
