182→
183→    // Validate auth_mode
184→    const authMode = body.auth_mode ?? "none";
185→    if (!VALID_AUTH_MODES.has(authMode)) {
186→      return jsonError(`Invalid auth_mode: must be one of none, static_headers, oauth, provider`, 400);
187→    }
188→
189→    // Encrypt static headers if provided
190→    let encryptedHeaders: EncryptedHeaderEntry[] | undefined;
191→    if (authMode === "static_headers") {
192→      const encryptionKey = deps.config.toolEncryptionKey;
193→      if (!encryptionKey) {
194→        log.error("mcp-server.create", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
195→        return jsonError("Server encryption not configured", 500);
196→      }
197→      if (!Array.isArray(body.static_headers) || body.static_headers.length === 0) {
198→        return jsonError("static_headers required when auth_mode is static_headers", 400);
199→      }
200→      // Validate header entries before encryption
201→      for (const header of body.static_headers) {
202→        if (!header.name || !header.value) {
203→          return jsonError("Each static header must have name and value", 400);
204→        }
205→      }
206→      const headerValidation = validateHeaders(
207→        body.static_headers as Array<{ name: string; value: string }>,
208→      );
209→      if (!headerValidation.ok) {
210→        return jsonError(headerValidation.error, 400);
211→      }
212→      encryptedHeaders = encryptHeaders(
213→        body.static_headers as Array<{ name: string; value: string }>,
214→        encryptionKey,
215→      );
216→    }
217→
218→    // Check duplicate name
219→    const duplicate = await serverNameExists(deps.surreal, workspaceRecord, body.name);
220→    if (duplicate) {
221→      return jsonError(`MCP server "${body.name}" already exists in this workspace`, 409);
222→    }
223→
224→    // Create server
225→    const row = await createMcpServer(deps.surreal, workspaceRecord, {
226→      name: body.name,
227→      url: urlString,
228→      transport,
229→      authMode,
230→      staticHeaders: encryptedHeaders,
231→      providerRecord,
232→    });
233→
234→    const response = toMcpServerResponse(row, providerName) as Record<string, unknown>;
235→
236→    // OAuth auto-discovery: probe the MCP server for OAuth metadata, create/find
237→    // provider, optionally register as dynamic client, then generate the
238→    // authorization URL so the frontend can redirect immediately.
239→    if (authMode === "oauth") {
240→      const authUrl = await autoDiscoverAndAuthorize(row, workspaceRecord);
241→      if (authUrl) {
242→        response.authorization_url = authUrl;
243→      }
244→    }
245→
246→    return jsonResponse(response, 201);
247→  }
