518→    } catch (error) {
519→      if (error instanceof HttpError) {
520→        return jsonError(error.message, error.status);
521→      }
522→      log.error("mcp-server.update-headers", "Failed to resolve workspace", error, { workspaceId });
523→      return jsonError("internal error", 500);
524→    }
525→
526→    let body: { headers?: Array<{ name?: string; value?: string }> };
527→    try {
528→      body = await request.json() as { headers?: Array<{ name?: string; value?: string }> };
529→    } catch {
530→      return jsonError("invalid JSON body", 400);
531→    }
532→
533→    if (!Array.isArray(body.headers)) {
534→      return jsonError("headers array is required", 400);
535→    }
536→
537→    const serverRecord = new RecordId("mcp_server", serverId);
538→
539→    // Empty headers array = clear all headers and reset auth_mode to "none"
540→    if (body.headers.length === 0) {
541→      const clearedRow = await clearMcpServerHeaders(
542→        deps.surreal,
543→        serverRecord,
544→        workspaceRecord,
545→      );
546→
547→      if (!clearedRow) {
