549→      }
550→
551→      return jsonResponse(toMcpServerResponse(clearedRow), 200);
552→    }
553→
554→    // Validate each header entry
555→    for (const header of body.headers) {
556→      if (!header.name || !header.value) {
557→        return jsonError("Each header must have name and value", 400);
558→      }
559→    }
560→    const headerValidation = validateHeaders(
561→      body.headers as Array<{ name: string; value: string }>,
562→    );
563→    if (!headerValidation.ok) {
564→      return jsonError(headerValidation.error, 400);
565→    }
566→
567→    const encryptionKey = deps.config.toolEncryptionKey;
568→    if (!encryptionKey) {
569→      log.error("mcp-server.update-headers", "TOOL_ENCRYPTION_KEY not configured", undefined, { workspaceId });
570→      return jsonError("Server encryption not configured", 500);
571→    }
572→
573→    const encryptedHeaders = encryptHeaders(
574→      body.headers as Array<{ name: string; value: string }>,
575→      encryptionKey,
576→    );
577→
578→    const updatedRow = await updateMcpServerHeaders(
579→      deps.surreal,
580→      serverRecord,
581→      workspaceRecord,
582→      encryptedHeaders,
583→    );
584→
585→    if (!updatedRow) {
586→      return jsonError("MCP server not found", 404);
587→    }
588→
589→    return jsonResponse(toMcpServerResponse(updatedRow), 200);
590→  }
