321→export async function listToolsWithCounts(
322→  surreal: Surreal,
323→  workspaceRecord: RecordId<"workspace", string>,
324→): Promise<ToolWithCountsRow[]> {
325→  const results = await surreal.query<[ToolWithCountsRow[]]>(
326→    `SELECT
327→       id,
