346→// ---------------------------------------------------------------------------
347→// Tool Detail Query (batched)
348→// ---------------------------------------------------------------------------
349→
350→/** Row shape for a single mcp_tool record. */
351→export type ToolDetailRow = {
352→  readonly id: RecordId<"mcp_tool", string>;
353→  readonly name: string;
354→  readonly toolkit: string;
355→  readonly description: string;
356→  readonly input_schema: Record<string, unknown>;
357→  readonly output_schema?: Record<string, unknown>;
358→  readonly risk_level: string;
359→  readonly status: string;
360→  readonly workspace: RecordId<"workspace", string>;
361→  readonly source_server?: RecordId<"mcp_server", string>;
362→  readonly created_at: Date;
363→};
364→
365→/** Row shape for a can_use grant edge with identity details. */
366→export type GrantDetailRow = {
367→  readonly identity_id: RecordId<"identity", string>;
368→  readonly identity_name: string;
369→  readonly max_calls_per_hour?: number;
370→  readonly granted_at: Date | string;
371→};
372→
373→/** Row shape for a governs_tool edge with policy details. */
374→export type GovernancePolicyDetailRow = {
375→  readonly policy_title: string;
376→  readonly policy_status: string;
377→  readonly conditions?: string;
378→  readonly max_per_call?: number;
379→  readonly max_per_day?: number;
380→};
381→
382→/**
383→ * Fetch tool detail with grants and governance policies in a single batched query.
384→ *
385→ * Returns undefined if the tool does not exist or does not belong to the workspace.
386→ */
387→export async function getToolDetail(
388→  surreal: Surreal,
389→  toolRecord: RecordId<"mcp_tool", string>,
390→  workspaceRecord: RecordId<"workspace", string>,
391→): Promise<
392→  | {
393→      tool: ToolDetailRow;
394→      grants: GrantDetailRow[];
395→      governancePolicies: GovernancePolicyDetailRow[];
396→    }
397→  | undefined
398→> {
399→  const results = await surreal.query<
400→    [ToolDetailRow[], GrantDetailRow[], GovernancePolicyDetailRow[]]
401→  >(
402→    `SELECT * FROM $tool WHERE workspace = $ws;
403→     SELECT in.id AS identity_id, in.name AS identity_name, max_calls_per_hour, granted_at FROM can_use WHERE out = $tool;
404→     SELECT in.title AS policy_title, in.status AS policy_status, conditions, max_per_call, max_per_day FROM governs_tool WHERE out = $tool;`,
405→    { tool: toolRecord, ws: workspaceRecord },
406→  );
407→
408→  const toolRows = results[0] ?? [];
409→  if (toolRows.length === 0) {
410→    return undefined;
411→  }
412→
413→  return {
414→    tool: toolRows[0],
415→    grants: results[1] ?? [],
416→    governancePolicies: results[2] ?? [],
417→  };
418→}
