420→// ---------------------------------------------------------------------------
421→// Grant Management Queries
422→// ---------------------------------------------------------------------------
423→
424→/**
425→ * Check if a can_use grant already exists between identity and tool.
426→ */
427→export async function grantExists(
428→  surreal: Surreal,
429→  identityRecord: RecordId<"identity", string>,
430→  toolRecord: RecordId<"mcp_tool", string>,
431→): Promise<boolean> {
432→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
433→    `SELECT id FROM can_use WHERE in = $identity AND out = $tool LIMIT 1;`,
434→    { identity: identityRecord, tool: toolRecord },
435→  );
436→  return (results[0] ?? []).length > 0;
437→}
438→
439→/**
440→ * Check if an identity record exists.
441→ */
442→export async function identityExists(
443→  surreal: Surreal,
444→  identityRecord: RecordId<"identity", string>,
445→): Promise<boolean> {
446→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
447→    `SELECT id FROM $identity;`,
448→    { identity: identityRecord },
449→  );
450→  return (results[0] ?? []).length > 0;
451→}
452→
453→/**
454→ * Check if an mcp_tool record exists in the given workspace.
455→ */
456→export async function toolExistsInWorkspace(
457→  surreal: Surreal,
458→  toolRecord: RecordId<"mcp_tool", string>,
459→  workspaceRecord: RecordId<"workspace", string>,
460→): Promise<boolean> {
461→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
462→    `SELECT id FROM $tool WHERE workspace = $ws LIMIT 1;`,
463→    { tool: toolRecord, ws: workspaceRecord },
464→  );
465→  return (results[0] ?? []).length > 0;
466→}
467→
468→/**
469→ * Create a can_use grant edge between identity and tool.
470→ * Uses RELATE for TYPE RELATION tables (per surrealdb.md).
471→ */
472→export async function createGrant(
473→  surreal: Surreal,
474→  identityRecord: RecordId<"identity", string>,
475→  toolRecord: RecordId<"mcp_tool", string>,
476→  maxCallsPerHour?: number,
477→): Promise<void> {
478→  const setClause = maxCallsPerHour !== undefined
479→    ? `SET granted_at = time::now(), max_calls_per_hour = $maxCallsPerHour`
480→    : `SET granted_at = time::now()`;
481→
482→  await surreal.query(
483→    `RELATE $identity->can_use->$tool ${setClause};`,
484→    { identity: identityRecord, tool: toolRecord, maxCallsPerHour },
485→  );
486→}
487→
488→/**
489→ * List all grants (can_use edges) for a tool, with identity details.
490→ */
491→export async function listGrantsForTool(
492→  surreal: Surreal,
493→  toolRecord: RecordId<"mcp_tool", string>,
