// OAuth pre-flight: probe the MCP server for OAuth metadata BEFORE creating
// the server record. If the auth server doesn't support dynamic client
// registration, fail early so the user can choose a different auth mode.
let oauthPreFlight: { authorizationUrl: string; error?: undefined } | undefined;
if (authMode === "oauth") {
  const result = await autoDiscoverAndAuthorize(urlString, workspaceRecord);
  if (result?.error) {
    return jsonError(
      `${result.error} Use "Static Headers" auth mode with an Authorization header instead.`,
      422,
    );
  }
  oauthPreFlight = result ?? undefined;
}

// Create server
const row = await createMcpServer(deps.surreal, workspaceRecord, {
  name: body.name,
  url: urlString,
  transport,
  authMode,
  staticHeaders: encryptedHeaders,
  providerRecord,
});

const response = toMcpServerResponse(row, providerName) as Record<string, unknown>;

// Link server to OAuth provider and attach authorization URL
if (oauthPreFlight?.authorizationUrl) {
  // Link the server to the provider created during pre-flight
  if (oauthPreFlight.authorizationUrl) {
    response.authorization_url = oauthPreFlight.authorizationUrl;
  }
}

return jsonResponse(response, 201);

