  1→/**
  2→ * Acceptance Tests: MCP OAuth 2.1 Discovery (US-2)
  3→ *
  4→ * Milestone 2: Brain auto-discovers OAuth requirements from MCP server URL
  5→ * using Protected Resource Metadata (RFC 9728) and Auth Server Metadata (RFC 8414).
  6→ * MSW simulates the external MCP server and OAuth authorization server.
  7→ *
  8→ * Traces: US-2, FR-2, AC-2a..AC-2f
  9→ * Driving port: POST /api/workspaces/:wsId/mcp-servers/:id/discover-auth
 10→ *
 11→ * Implementation sequence:
 12→ *   1. Discover auth from Protected Resource Metadata              [@skip]
 13→ *   2. Discover auth from WWW-Authenticate header on 401           [@skip]
 14→ *   3. Auth server metadata with path component (multi-fallback)   [@skip]
 15→ *   4. Discovery fails gracefully (no metadata)                    [@skip]
 16→ *   5. Auto-created credential_provider from discovery             [@skip]
 17→ */
 18→import { describe, expect, it, afterAll, beforeAll } from "bun:test";
 19→import { RecordId } from "surrealdb";
 20→import {
 21→  setupAcceptanceSuite,
 22→  createTestUserWithMcp,
 23→  setupMockMcpServer,
 24→} from "./mcp-server-auth-test-kit";
 25→import { http, HttpResponse } from "msw";
 26→import { setupServer as setupMswServer } from "msw/node";
 27→
 28→const getRuntime = setupAcceptanceSuite("mcp_server_auth_oauth_discovery");
 29→
 30→// ---------------------------------------------------------------------------
 31→// Milestone 2: OAuth 2.1 Discovery
 32→// ---------------------------------------------------------------------------
 33→describe("Discover auth from Protected Resource Metadata", () => {
 34→  it("fetches .well-known/oauth-protected-resource and auth server metadata", async () => {
 35→    const { baseUrl, surreal } = getRuntime();
 36→    const user = await createTestUserWithMcp(baseUrl, surreal, `ws-disc-${crypto.randomUUID()}`);
 37→
 38→    // Given MSW mock MCP server with Protected Resource Metadata
 39→    const { msw } = setupMockMcpServer({
 40→      mcpServerUrl: "https://mcp.example.com",
 41→      authServerUrl: "https://auth.example.com",
 42→      scopesSupported: ["tools:read", "tools:execute"],
 43→    });
 44→    msw.listen({ onUnhandledRequest: "bypass" });
 45→
 46→    try {
 47→      // And an MCP server record exists
 48→      const createResponse = await user.mcpFetch(
 49→        `/api/workspaces/${user.workspaceId}/mcp-servers`,
 50→        {
 51→          method: "POST",
 52→          body: {
 53→            name: "oauth-test",
 54→            url: "https://mcp.example.com",
 55→            transport: "streamable-http",
 56→            auth_mode: "oauth",
 57→          },
 58→        },
 59→      );
 60→      const { id: serverId } = await createResponse.json() as { id: string };
 61→
 62→      // When admin triggers OAuth discovery
 63→      const discoverResponse = await user.mcpFetch(
 64→        `/api/workspaces/${user.workspaceId}/mcp-servers/${serverId}/discover-auth`,
 65→        { method: "POST" },
 66→      );
 67→
 68→      // Then discovery succeeds with auth server details
 69→      expect(discoverResponse.status).toBe(200);
 70→      const body = await discoverResponse.json() as Record<string, unknown>;
 71→      expect(body.discovered).toBe(true);
 72→      expect(body.auth_server).toBe("https://auth.example.com");
 73→      expect(body.authorization_endpoint).toBe("https://auth.example.com/authorize");
 74→    } finally {
 75→      msw.close();
 76→    }
 77→  }, 30_000);
 78→});
 79→
 80→describe("Discover auth from WWW-Authenticate header on 401", () => {
 81→  it("falls back to WWW-Authenticate when .well-known is not available", async () => {
 82→    const { baseUrl, surreal } = getRuntime();
 83→    const user = await createTestUserWithMcp(baseUrl, surreal, `ws-www-auth-${crypto.randomUUID()}`);
 84→
 85→    // Given MCP server does NOT serve /.well-known/oauth-protected-resource
 86→    // But returns 401 with WWW-Authenticate: Bearer resource_metadata="..."
 87→    // The resource_metadata URL in the header can be any URL (not necessarily the well-known path)
 88→    const mcpServerUrl = "https://mcp-no-wellknown.example.com";
 89→    const authServerUrl = "https://auth-wwwauth.example.com";
 90→    const wellKnownUrl = `${mcpServerUrl}/.well-known/oauth-protected-resource`;
 91→    const resourceMetadataUrl = `${mcpServerUrl}/oauth/resource-metadata`;
 92→
 93→    const msw = setupMswServer(
 94→      // Standard .well-known returns 404 (not available)
 95→      http.get(wellKnownUrl, () => {
 96→        return new HttpResponse(null, { status: 404 });
 97→      }),
 98→
 99→      // MCP server returns 401 with WWW-Authenticate header pointing to resource metadata
100→      http.post(mcpServerUrl, () => {
101→        return new HttpResponse(null, {
102→          status: 401,
103→          headers: {
104→            "WWW-Authenticate": `Bearer resource_metadata="${resourceMetadataUrl}"`,
105→          },
106→        });
107→      }),
108→
109→      // The resource_metadata URL (from WWW-Authenticate) returns Protected Resource Metadata
110→      http.get(resourceMetadataUrl, () => {
