280→// ---------------------------------------------------------------------------
281→// Discovery Types
282→// ---------------------------------------------------------------------------
283→
284→export type ToolSyncAction = "create" | "update" | "disable" | "unchanged";
285→
286→/**
287→ * A single tool found during MCP server discovery with its sync action.
288→ */
