305→
306→// ---------------------------------------------------------------------------
307→// OAuth Discovery Types (RFC 9728 + RFC 8414)
308→// ---------------------------------------------------------------------------
309→
310→/**
311→ * Protected Resource Metadata (RFC 9728).
312→ * Returned by /.well-known/oauth-protected-resource on the MCP server.
313→ */
314→export type ProtectedResourceMetadata = {
