183→/**
184→ * Delete an mcp_server, disable linked tools, and cascade-delete the linked
185→ * credential_provider + connected_accounts if no other server references
186→ * the same provider.
187→ *
188→ * Returns true if the server existed and was deleted.
189→ */
190→export async function deleteMcpServer(
191→  surreal: Surreal,
192→  serverRecord: RecordId<"mcp_server", string>,
193→  workspaceRecord: RecordId<"workspace", string>,
194→): Promise<boolean> {
195→  // Check existence and capture provider reference before deletion
196→  const existing = await getMcpServerById(surreal, serverRecord, workspaceRecord);
197→  if (!existing) {
198→    return false;
199→  }
200→
201→  const providerRef = existing.provider;
202→
203→  // Disable all tools linked to this server, then delete the server
204→  await surreal.query(
205→    `UPDATE mcp_tool SET status = "disabled" WHERE source_server = $server;
206→     DELETE $server;`,
207→    { server: serverRecord },
208→  );
209→
210→  // Cascade-delete provider if no other server references it
211→  if (providerRef) {
212→    const [otherServers] = await surreal.query<[Array<{ id: RecordId }>]>(
213→      `SELECT id FROM mcp_server WHERE provider = $provider LIMIT 1;`,
214→      { provider: providerRef },
215→    );
216→
217→    if ((otherServers ?? []).length === 0) {
218→      // Orphaned provider — delete connected_accounts first, then the provider
219→      await surreal.query(
220→        `DELETE connected_account WHERE provider = $provider;
221→         DELETE $provider;`,
222→        { provider: providerRef },
223→      );
224→    }
225→  }
226→
227→  return true;
228→}
