307→/**
308→ * Auth status for an MCP server's OAuth connection.
309→ */
310→export type McpServerAuthStatusResult = {
311→  auth_status: "connected" | "expired" | "error" | "not_authorized" | "none";
312→};
313→
314→/**
315→ * Determine the auth status for an MCP server.
316→ *
317→ * - "connected": has oauth_account with active status
318→ * - "expired": has oauth_account but status is expired
319→ * - "error": last_status is auth_error
320→ * - "not_authorized": auth_mode is oauth but no oauth_account
321→ * - "none": auth_mode is not oauth
322→ */
323→export async function getMcpServerAuthStatus(
324→  surreal: Surreal,
325→  serverRecord: RecordId<"mcp_server", string>,
326→  workspaceRecord: RecordId<"workspace", string>,
327→): Promise<McpServerAuthStatusResult | undefined> {
328→  const server = await getMcpServerById(surreal, serverRecord, workspaceRecord);
329→  if (!server) return undefined;
330→
331→  if (server.auth_mode !== "oauth") {
332→    return { auth_status: "none" };
333→  }
334→
335→  if (!server.oauth_account) {
336→    return { auth_status: "not_authorized" };
337→  }
338→
339→  // Check the connected_account status first -- it takes priority over last_status
340→  const [accountRows] = await surreal.query<[Array<{ status: string }>]>(
341→    `SELECT status FROM $acct;`,
342→    { acct: server.oauth_account },
343→  );
344→  const account = (accountRows ?? [])[0];
345→
346→  if (!account) {
347→    return { auth_status: "not_authorized" };
348→  }
349→
350→  if (account.status === "expired") {
351→    return { auth_status: "expired" };
352→  }
353→
354→  if (account.status === "active") {
355→    return { auth_status: "connected" };
356→  }
357→
358→  // Fallback: last_status = auth_error or other non-active/non-expired states
359→  if (server.last_status === "auth_error") {
360→    return { auth_status: "error" };
361→  }
362→
363→  return { auth_status: "error" };
364→}
365→
