371→  surreal: Surreal,
372→  serverRecord: RecordId<"mcp_server", string>,
373→): Promise<void> {
374→  await surreal.query(
375→    `UPDATE $server SET pending_pkce_verifier = NONE, pending_oauth_state = NONE;`,
376→    { server: serverRecord },
377→  );
378→}
