691→// ---------------------------------------------------------------------------
692→// DPoP Helpers
693→// ---------------------------------------------------------------------------
694→
695→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
696→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
697→    { name: "ECDSA", namedCurve: "P-256" },
698→    true,
699→    ["sign", "verify"],
700→  );
701→
702→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
703→  const thumbprint = await computeDPoPThumbprint(publicJwk);
704→
705→  return { privateKey, publicKey, publicJwk, thumbprint };
706→}
707→
708→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
709→  const thumbprintInput = JSON.stringify({
710→    crv: publicJwk.crv,
711→    kty: publicJwk.kty,
712→    x: publicJwk.x,
713→    y: publicJwk.y,
714→  });
715→
716→  const hashBuffer = await crypto.subtle.digest(
717→    "SHA-256",
718→    new TextEncoder().encode(thumbprintInput),
719→  );
720→
721→  return base64urlBytes(new Uint8Array(hashBuffer));
722→}
723→
724→async function createDPoPProof(
725→  keyPair: DPoPKeyPair,
726→  method: string,
727→  targetUri: string,
728→): Promise<string> {
729→  const header = {
730→    typ: "dpop+jwt" as const,
731→    alg: "ES256" as const,
732→    jwk: {
733→      kty: keyPair.publicJwk.kty,
734→      crv: keyPair.publicJwk.crv,
735→      x: keyPair.publicJwk.x,
736→      y: keyPair.publicJwk.y,
737→    },
738→  };
739→
740→  const payload = {
741→    jti: crypto.randomUUID(),
742→    htm: method,
743→    htu: targetUri,
744→    iat: Math.floor(Date.now() / 1000),
745→  };
746→
747→  const importedKey = await jose.importJWK(
748→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
749→    "ES256",
750→  );
751→
752→  return await new jose.SignJWT(payload)
753→    .setProtectedHeader(header)
754→    .sign(importedKey);
755→}
756→
757→function base64urlBytes(bytes: Uint8Array): string {
758→  const binary = String.fromCharCode(...bytes);
759→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
760→}
