 58→
 59→type McpServerResponse = {
 60→  id: string;
 61→  name: string;
 62→  url: string;
 63→  transport: string;
 64→  auth_mode: string;
 65→  has_static_headers: boolean;
 66→  tool_count: number;
 67→  last_status?: string;
 68→  last_error?: string;
 69→  last_discovery?: string;
 70→  provider_id?: string;
 71→  provider_name?: string;
 72→  created_at: string;
 73→};
 74→
 75→function toMcpServerResponse(
 76→  row: McpServerRow,
 77→  providerName?: string,
 78→): McpServerResponse {
 79→  const response: McpServerResponse = {
 80→    id: row.id.id as string,
 81→    name: row.name,
 82→    url: row.url,
 83→    transport: row.transport,
 84→    auth_mode: row.auth_mode ?? "none",
 85→    has_static_headers: Array.isArray(row.static_headers) && row.static_headers.length > 0,
 86→    tool_count: row.tool_count,
 87→    created_at: row.created_at instanceof Date
 88→      ? row.created_at.toISOString()
 89→      : String(row.created_at),
 90→  };
 91→
 92→  if (row.last_status) {
 93→    response.last_status = row.last_status;
 94→  }
 95→  if (row.last_error) {
 96→    response.last_error = row.last_error;
 97→  }
 98→  if (row.last_discovery) {
 99→    response.last_discovery = row.last_discovery instanceof Date
100→      ? row.last_discovery.toISOString()
101→      : String(row.last_discovery);
102→  }
103→  if (row.provider) {
104→    response.provider_id = row.provider.id as string;
105→    if (providerName) {
106→      response.provider_name = providerName;
107→    }
108→  }
109→
110→  return response;
111→}
