111→// Helper: base64url encode an ArrayBuffer (no padding)
112→function base64UrlEncode(buffer: ArrayBuffer): string {
113→  const bytes = new Uint8Array(buffer);
114→  let binary = "";
115→  for (const byte of bytes) {
116→    binary += String.fromCharCode(byte);
117→  }
118→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
119→}
