 44→async function resolveIdentityFromSession(
 45→  deps: ServerDependencies,
 46→  request: Request,
 47→): Promise<RecordId<"identity", string> | Response> {
 48→  const session = await deps.auth.api.getSession({ headers: request.headers });
 49→  if (!session?.user?.id) {
 50→    return jsonError("authentication required", 401);
 51→  }
 52→
 53→  const personRecord = new RecordId("person", session.user.id);
 54→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
 55→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 56→    { person: personRecord },
 57→  );
 58→  const identityRecord = identityRows[0] as RecordId<"identity", string> | undefined;
 59→  if (!identityRecord) {
 60→    return jsonError("identity not found for user", 500);
 61→  }
 62→
 63→  return identityRecord;
 64→}
